import{_ as t,o as l,c as r,a2 as e}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 外交系統詳解：戰爭不是唯一選項","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/diplomacy-guide.md","filePath":"bannerlord/diplomacy-guide.md"}'),i={name:"bannerlord/diplomacy-guide.md"};function o(d,a,h,n,s,u){return l(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="騎砍2-外交系統詳解-戰爭不是唯一選項" tabindex="-1">騎砍2 | 外交系統詳解：戰爭不是唯一選項 <a class="header-anchor" href="#騎砍2-外交系統詳解-戰爭不是唯一選項" aria-label="Permalink to &quot;騎砍2 | 外交系統詳解：戰爭不是唯一選項&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>原版騎砍2的外交很陽春——宣戰、停戰、沒了。但即便在這樣的限制下，懂得操控外交的人，可以用最小代價統一全大陸。</p><hr><h2 id="一、宣戰機制" tabindex="-1">一、宣戰機制 <a class="header-anchor" href="#一、宣戰機制" aria-label="Permalink to &quot;一、宣戰機制&quot;">​</a></h2><h3 id="_1-1-為什麼會開戰" tabindex="-1">1.1 為什麼會開戰 <a class="header-anchor" href="#_1-1-為什麼會開戰" aria-label="Permalink to &quot;1.1 為什麼會開戰&quot;">​</a></h3><ul><li>領主投票通過宣戰</li><li>邊境衝突升級（掠奪村莊、攻擊商隊）</li><li>勢力平衡打破（某國太弱就會被圍毆）</li></ul><h3 id="_1-2-什麼時候該宣戰" tabindex="-1">1.2 什麼時候該宣戰 <a class="header-anchor" href="#_1-2-什麼時候該宣戰" aria-label="Permalink to &quot;1.2 什麼時候該宣戰&quot;">​</a></h3><table tabindex="0"><thead><tr><th>時機</th><th>原因</th></tr></thead><tbody><tr><td>目標國正在跟另一國打仗</td><td>雙線作戰，分身乏術</td></tr><tr><td>目標國剛打完大仗</td><td>兵力尚未恢復</td></tr><tr><td>目標國有領主不滿</td><td>打完可以挖角</td></tr></tbody></table><h3 id="_1-3-什麼時候不該宣戰" tabindex="-1">1.3 什麼時候不該宣戰 <a class="header-anchor" href="#_1-3-什麼時候不該宣戰" aria-label="Permalink to &quot;1.3 什麼時候不該宣戰&quot;">​</a></h3><ul><li>你自己才剛打完仗，兵力還沒恢復</li><li>目標國是當前的霸主（你打不贏）</li><li>你跟其他國還有戰事（不要雙線）</li></ul><hr><h2 id="二、停戰談判" tabindex="-1">二、停戰談判 <a class="header-anchor" href="#二、停戰談判" aria-label="Permalink to &quot;二、停戰談判&quot;">​</a></h2><h3 id="_2-1-停戰條件" tabindex="-1">2.1 停戰條件 <a class="header-anchor" href="#_2-1-停戰條件" aria-label="Permalink to &quot;2.1 停戰條件&quot;">​</a></h3><p>發起停戰 → 跟對方國王見面 → 談判條件：</p><ul><li><strong>你佔優勢</strong>：可以要求對方付戰爭賠款</li><li><strong>平手</strong>：雙方互不支付</li><li><strong>你劣勢</strong>：你必須付錢才能停戰</li></ul><h3 id="_2-2-何時該停戰" tabindex="-1">2.2 何時該停戰 <a class="header-anchor" href="#_2-2-何時該停戰" aria-label="Permalink to &quot;2.2 何時該停戰&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情境</th><th>行動</th></tr></thead><tbody><tr><td>你已達成戰爭目標（佔了想要的城）</td><td>立刻停戰</td></tr><tr><td>對方軍團比你的大兩倍</td><td>花錢停戰，不要硬撐</td></tr><tr><td>有第三國趁亂宣你</td><td>立刻跟第一國停戰</td></tr></tbody></table><hr><h2 id="三、影響力系統" tabindex="-1">三、影響力系統 <a class="header-anchor" href="#三、影響力系統" aria-label="Permalink to &quot;三、影響力系統&quot;">​</a></h2><h3 id="_3-1-影響力怎麼來" tabindex="-1">3.1 影響力怎麼來 <a class="header-anchor" href="#_3-1-影響力怎麼來" aria-label="Permalink to &quot;3.1 影響力怎麼來&quot;">​</a></h3><ul><li>參加軍團打仗</li><li>捐贈俘虜給領主城鎮</li><li>捐贈士兵給領主</li><li>政策加成</li></ul><h3 id="_3-2-影響力怎麼用" tabindex="-1">3.2 影響力怎麼用 <a class="header-anchor" href="#_3-2-影響力怎麼用" aria-label="Permalink to &quot;3.2 影響力怎麼用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>用途</th><th>消耗</th></tr></thead><tbody><tr><td>創建軍團</td><td>依規模</td></tr><tr><td>提案政策</td><td>50-100</td></tr><tr><td>否決他人提案</td><td>依提案</td></tr><tr><td>提名封地歸屬</td><td>依影響力</td></tr></tbody></table><blockquote><p>💡 影響力就是政治資本。存著關鍵時刻用，不要隨便花。</p></blockquote><hr><h2 id="四、裝-diplomacy-mod-之後" tabindex="-1">四、裝 Diplomacy MOD 之後 <a class="header-anchor" href="#四、裝-diplomacy-mod-之後" aria-label="Permalink to &quot;四、裝 Diplomacy MOD 之後&quot;">​</a></h2><p>原版外交太簡陋，裝了 Diplomacy MOD 後會加入：</p><ul><li><strong>互不侵犯條約</strong>：雙方約定一段時間內不打</li><li><strong>聯盟</strong>：A 國打 B 國 = 你的盟國也會自動參戰</li><li><strong>威脅</strong>：要求對方割讓領地，不從就宣戰</li><li><strong>附庸</strong>：對方變成你的附庸國，付貢金</li><li><strong>分封系統</strong>：更複雜的領主關係</li></ul><blockquote><p>這 MOD 是自立為王玩家的標配。詳見 <a href="./mod-recommendations.html">騎砍2 | 2026 必裝 MOD 推薦</a>。</p></blockquote><hr><h2 id="五、戰爭以外的手段" tabindex="-1">五、戰爭以外的手段 <a class="header-anchor" href="#五、戰爭以外的手段" aria-label="Permalink to &quot;五、戰爭以外的手段&quot;">​</a></h2><h3 id="_5-1-經濟壓制" tabindex="-1">5.1 經濟壓制 <a class="header-anchor" href="#_5-1-經濟壓制" aria-label="Permalink to &quot;5.1 經濟壓制&quot;">​</a></h3><ul><li>掠奪敵國村莊 → 原料停產 → 城鎮收入下降</li><li>攻擊敵國商隊 → 斷他們財路</li><li>買下敵國城鎮的工廠 → 再賣掉（搞亂他們經濟）</li></ul><h3 id="_5-2-政治滲透" tabindex="-1">5.2 政治滲透 <a class="header-anchor" href="#_5-2-政治滲透" aria-label="Permalink to &quot;5.2 政治滲透&quot;">​</a></h3><ul><li>挖角敵方領主 → 帶走封地 → 敵國變弱</li><li>支持敵國內部的叛軍 → 內部不穩</li><li>跟敵國的敵國結盟 → 形成包圍網</li></ul><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./kingdom-building.html">騎砍2 | 自立為王</a></li><li><a href="./kingdom-management.html">騎砍2 | 王國管理深度指南</a></li><li><a href="./lord-loyalty.html">騎砍2 | 領主忠誠與叛變預防</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',45)])])}const m=t(i,[["render",o]]);export{b as __pageData,m as default};
